const sd = $getWorkflowStaticData('global');
sd.vips = sd.vips || [];
const setup = $('⚙️ Setup').first().json;
const orders = ($json.orders || []).filter(o => !o.cancelled_at && o.email && o.customer);
const umsatzSchwelle = parseFloat(setup.VIP_UMSATZ_SCHWELLE);
const bestellSchwelle = parseInt(setup.VIP_BESTELLUNGEN_SCHWELLE);
const raus = [];

for (const o of orders) {
  const k = o.customer;
  const totalSpent = parseFloat(k.total_spent || 0);
  const ordersCount = parseInt(k.orders_count || 0);
  const istVip = totalSpent >= umsatzSchwelle || ordersCount >= bestellSchwelle;
  if (!istVip) continue;
  if (sd.vips.includes(k.id)) continue; // war schon VIP
  sd.vips.push(k.id);

  const artikel = (o.line_items || []).map(li => li.title).slice(0, 3).join(', ');
  const prompt = 'Du schreibst im Namen des Gruenders vom Onlineshop "' + setup.SHOP_NAME + '".\n' +
    'Dieser Kunde ist gerade offiziell VIP geworden: ' + ordersCount + ' Bestellungen, ' + totalSpent.toFixed(0) + ' Gesamtumsatz. Letzte Bestellung: ' + artikel + '.\n\n' +
    'Schreibe eine PERSOENLICHE Dankes-E-Mail auf Deutsch (Du-Form), maximal 120 Woerter:\n' +
    '- Klingt wie vom Gruender persoenlich getippt, NICHT wie Marketing\n' +
    '- Ehrlicher Dank, dass er/sie immer wieder kauft\n' +
    '- Vorname: ' + (k.first_name || 'unbekannt (neutral anreden)') + '\n' +
    '- Als Dankeschoen: exklusiver VIP-Code ' + setup.VIP_RABATT_CODE + ' (dauerhaft gueltig, nur fuer ihn/sie)\n' +
    '- Frage am Ende: "Was koennen wir besser machen?" (echte Antworten erwuenscht)\n' +
    '- Schlichtes HTML, wenig Styling, wie eine normale persoenliche Mail\n' +
    'Antworte NUR mit validem JSON, ohne Markdown-Codeblock: {"betreff": "...", "html": "..."}';

  raus.push({ json: {
    email: o.email,
    vorname: k.first_name || '',
    total_spent: totalSpent.toFixed(2),
    orders_count: ordersCount,
    prompt
  }});
}

if (sd.vips.length > 5000) sd.vips = sd.vips.slice(-5000);
return raus;

const blocks = $json.content || [];
const text = (blocks.find(b => b.type === 'text') || {}).text || '';
let daten;
try {
  daten = JSON.parse(text.replace(/```json|```/g, '').trim());
} catch (e) {
  daten = { betreff: 'Danke, dass du dabei bist 💛', html: text };
}
const orig = $('👑 Neue VIPs erkennen').item.json;
const setup = $('⚙️ Setup').first().json;
const empfaenger = setup.TEST_MODE === 'ja' ? setup.OWNER_EMAIL : orig.email;

const telegram_text = '👑 NEUER VIP-KUNDE!\n\n' +
  'Name: ' + (orig.vorname || '?') + '\nE-Mail: ' + orig.email + '\n' +
  'Bestellungen: ' + orig.orders_count + '\nGesamtumsatz: ' + orig.total_spent + '\n\n' +
  'Persoenliche Dankes-Mail wurde ' + (setup.TEST_MODE === 'ja' ? 'im TEST-MODUS an dich' : 'automatisch an den Kunden') + ' gesendet. 💌';

return { json: {
  empfaenger,
  betreff: (setup.TEST_MODE === 'ja' ? '[TEST] ' : '') + daten.betreff,
  email_html: daten.html,
  telegram_text
}};
